code.python:
def find_disappeared_numbers(nums):
    present = set(nums)
    out = []
    for i in range(1, len(nums) + 1):
        if i not in present:
            out.append(i)
    return out

code.javascript:
function findDisappearedNumbers(nums) {
  const present = new Set(nums);
  const out = [];
  for (let i = 1; i <= nums.length; i++) {
    if (!present.has(i)) {
      out.push(i);
    }
  }
  return out;
}

code.typescript:
function findDisappearedNumbers(nums: number[]): number[] {
  const present = new Set(nums);
  const out: number[] = [];
  for (let i = 1; i <= nums.length; i++) {
    if (!present.has(i)) {
      out.push(i);
    }
  }
  return out;
}
